			pivotPoints[p_idx++] = startsAt + (we_need/histogram[i]) * histo_width;
			startsAt = startsAt + ((we_need/histogram[i]) * histo_width); 
			histogram[i] -= we_need; 
			we_need = elemsPerSlice; 
		}

		we_need -= histogram[i]; 

		startsAt = endsAt; 
		endsAt += histo_width; 
	}
	while(p_idx < divisions){
		pivotPoints[p_idx] = pivotPoints[p_idx-1]; 
		p_idx++; 
	}
}

