#define DIVISIONS		(1 << LOG_DIVISIONS)

#define BUCKET_WARP_LOG_SIZE	5
#define BUCKET_WARP_N			1
#ifdef BUCKET_WG_SIZE_1
#define BUCKET_THREAD_N BUCKET_WG_SIZE_1
#else
#define BUCKET_THREAD_N			(BUCKET_WARP_N << BUCKET_WARP_LOG_SIZE)
#endif
#define BUCKET_BLOCK_MEMORY		(DIVISIONS * BUCKET_WARP_N)
#define BUCKET_BAND				128

// Helper function to perform atomic increment with thread tagging
// Simulates the CUDA volatile spinlock using OpenCL atomics
unsigned int addOffset(volatile unsigned int *s_offset, unsigned int data, unsigned int threadTag){
    unsigned int current = s_offset[data];
    unsigned int count_val = current & 0x07FFFFFFU;
    unsigned int next_count = count_val + 1;
    unsigned int target = threadTag | next_count;

    // Atomic compare-and-swap loop
    while (atomic_cmpxchg(&s_offset[data], current, target) != current) {
        current = s_offset[data];
        count_val = current & 0x07FFFFFFU;
        next_count = count_val + 1;
        target = threadTag | next_count;
    }

    return next_count - 1;
}

__kernel void
bucketcount(float *input, int *indice, unsigned int *d_prefixoffsets, int size, float *pivotPoints)
{
    volatile __local unsigned int s_offset[BUCKET_BLOCK_MEMORY]; 

    const int tid = get_global_id(0);
    const int local_id = get_local_id(0);
    const int block_id = get_group_id(0);
    const int num_threads = get_global_size(0);

    const unsigned int threadTag = local_id << (32 - BUCKET_WARP_LOG_SIZE);
    const int warpBase = (local_id >> BUCKET_WARP_LOG_SIZE) * DIVISIONS; 

    // Initialize local memory
    for (int i = local_id; i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
        s_offset[i] = 0; 

    barrier(CLK_LOCAL_MEM_FENCE); 

    for (int t = tid; t < size; t += num_threads) {
        float elem = input[t]; 

        int idx  = DIVISIONS/2 - 1; 
        int jump = DIVISIONS/4; 
        float piv = pivotPoints[idx]; 

        while(jump >= 1){
            idx = (elem < piv) ? (idx - jump) : (idx + jump);
            piv = pivotPoints[idx]; 
            jump /= 2; 
        }
        idx = (elem < piv) ? idx : (idx + 1); 

        indice[t] = (addOffset(s_offset + warpBase, idx, threadTag) << LOG_DIVISIONS) + idx;  
    }

    barrier(CLK_LOCAL_MEM_FENCE); 

    int prefixBase = block_id * BUCKET_BLOCK_MEMORY; 

    for (int i = local_id; i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
        d_prefixoffsets[prefixBase + i] = s_offset[i] & 0x07FFFFFFU; 
}

__kernel void bucketprefixoffset(unsigned int *d_prefixoffsets, unsigned int *d_offsets, int blocks) {
    int tid = get_global_id(0);
    int size = blocks * BUCKET_BLOCK_MEMORY; 
    int sum = 0; 

    // Each thread sums a column (division index) across all blocks
    // Step size is DIVISIONS (which equals BUCKET_BLOCK_MEMORY in this config)
    // Only threads with tid < DIVISIONS produce valid output for d_offsets
    if (tid < DIVISIONS) {
        for (int i = tid; i < size; i += DIVISIONS) {
            int x = d_prefixoffsets[i]; 
            d_prefixoffsets[i] = sum; 
            sum += x; 
        }
        d_offsets[tid] = sum; 
    } else {
        // Threads beyond DIVISIONS still need to update the prefix offsets array 
        // if the grid size is larger than DIVISIONS, though typically grid matches DIVISIONS.
        // If grid is larger, these threads would process indices >= DIVISIONS which might not exist 
        // or be handled differently. Assuming standard usage where global size == DIVISIONS.
        // However, to be safe and match CUDA behavior where 'tid' iterates:
        for (int i = tid; i < size; i += DIVISIONS) {
            int x = d_prefixoffsets[i]; 
            d_prefixoffsets[i] = sum; 
            sum += x; 
        }
    }
}

__kernel void
bucketsort(float *input, int *indice, float *output, int size, unsigned int *d_prefixoffsets, 
		   unsigned int *l_offsets)
{
    volatile __local unsigned int s_offset[BUCKET_BLOCK_MEMORY]; 

    int local_id = get_local_id(0);
    int block_id = get_group_id(0);
    int tid = get_global_id(0);
    int num_threads = get_global_size(0);

    int prefixBase = block_id * BUCKET_BLOCK_MEMORY; 
    const int warpBase = (local_id >> BUCKET_WARP_LOG_SIZE) * DIVISIONS; 

    // Initialize local memory with offsets
    for (int i = local_id; i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
        s_offset[i] = l_offsets[i & (DIVISIONS - 1)] + d_prefixoffsets[prefixBase + i]; 

    barrier(CLK_LOCAL_MEM_FENCE); 

    for (int t = tid; t < size; t += num_threads) {
        int id = indice[t]; 
        int dest_idx = s_offset[warpBase + (id & (DIVISIONS - 1))] + (id >> LOG_DIVISIONS);
        output[dest_idx] = input[t];
    }
}

